// Solution
function validatePortMappings(service) {
    if (service.ports.length === 0) return true;
    let portSet = new Set();
    for (let port of service.ports) {
        if (port < 1024 || port > 65535) return false;
        if (portSet.has(port)) return false;
        portSet.add(port);
    }
    return true;
}

