class Solution:
    def validatePortMappings(self, service: dict) -> bool:
        if len(service['ports']) == 0: return True
        portSet = set()
        for port in service['ports']:
            if port < 1024 or port > 65535: return False
            if port in portSet: return False
            portSet.add(port)
        return True
